public class Player {
    String name;    // field
    int hp;         // field
    int level;      // field

    // Constructor:
    public Player(String name, int hp) {
        this.name = name;  // this = current object
        this.hp = hp;
        this.level = 1;    // default
    }

    public void attack() {
        System.out.println(name + " attacks!");
    }

    public String toString() {
        return name + " [HP:" + hp + " LV:" + level + "]";
    }
}

Player p = new Player("Neo", 100);
p.attack();          // Neo attacks!
System.out.println(p); // Neo [HP:100 LV:1]

