public class Circle {
    double radius;  // field

    public Circle(double radius) {  // param same name
        this.radius = radius; // this.radius = field
        //     radius = radius; // WRONG — param = param
    }

    public double area() {
        return Math.PI * this.radius * this.radius;
        // 'this.radius' same as 'radius' here (no ambiguity)
    }
}

