public class Player {
    // static: shared by ALL players:
    private static int totalPlayers = 0;
    public static final int MAX_HP = 100; // constant

    // instance: per-player
    private String name;
    private int hp;

    public Player(String name) {
        this.name = name;
        this.hp = MAX_HP;
        totalPlayers++;  // update shared counter
    }

    public static int getTotal() {
        return totalPlayers;  // no 'this' here
    }
}

new Player("Neo");
new Player("Trinity");
System.out.println(Player.getTotal()); // 2
System.out.println(Player.MAX_HP);     // 100

